using System.Collections;
using UnityEngine;

/// <summary>
/// Muda o estado de reação deste NPC (NpcController.SetReactionState) — actualiza
/// o parâmetro Int do Animator e/ou troca o sprite, consoante configurado no
/// NpcController, e fica disponível para Condition_NpcReactionState (ex: um
/// evento de Touch só ataca se o NPC estiver Hostile, ou só conversa se Friendly).
/// </summary>
[System.Serializable]
public class Action_SetReactionState : NpcAction
{
    public NpcReactionState state = NpcReactionState.Idle;

    [Tooltip("Som opcional a tocar ao mudar de estado (ex: um grunhido ao ficar Hostile, ou um \"chilrear\" ao ficar Surprised).")]
    public AudioClip sfx;

    public override IEnumerator Execute(NpcController npc)
    {
        npc.SetReactionState(state);

        if (sfx != null)
            AudioManager.Instance?.PlaySE(sfx);

        yield break;
    }
}
